#=========================================================================
# crt0_test.S : Entry point for Zeppelin assembly tests
#=========================================================================
# Derived from app/scripts/crt0.S.
#
# Unlike the app crt0, this startup is designed for pure assembly test
# programs (e.g. generated by riscv-dv). There is no C main() to call;
# instead, control is handed off to test_entry, a label that each
# assembly test file must define. When test_entry returns, the exit
# peripheral is written to terminate the simulation.

  .text
  .global _start
  .global test_return
_start:

  # initialize global pointer

  auipc gp, %pcrel_hi(_gp)
  addi  gp, gp, %pcrel_lo(_start)

  # initialize all registers to zero. this helps four-state simulation by
  # making sure no register values are Xs.

  addi  x1,  x0, 0
  addi  x2,  x0, 0
  # ... x3 is gp which was initialized above ...
  addi  x4,  x0, 0
  addi  x5,  x0, 0
  addi  x6,  x0, 0
  addi  x7,  x0, 0
  addi  x8,  x0, 0
  addi  x9,  x0, 0
  addi  x10, x0, 0
  addi  x11, x0, 0
  addi  x12, x0, 0
  addi  x13, x0, 0
  addi  x14, x0, 0
  addi  x15, x0, 0
  addi  x16, x0, 0
  addi  x17, x0, 0
  addi  x18, x0, 0
  addi  x19, x0, 0
  addi  x20, x0, 0
  addi  x21, x0, 0
  addi  x22, x0, 0
  addi  x23, x0, 0
  addi  x24, x0, 0
  addi  x25, x0, 0
  addi  x26, x0, 0
  addi  x27, x0, 0
  addi  x28, x0, 0
  addi  x29, x0, 0
  addi  x30, x0, 0
  addi  x31, x0, 0

  # initialize stack pointer to 0xff000

  lui   sp, 0x000ff

1:

  # clear the bss segment

  la    t0, _fbss   # _fbss is defined in linker script
  la    t1, _end    # _fbss is defined in linker script

1:
  sw    x0, 0(t0)
  addi  t0, t0, 4
  bltu  t0, t1, 1b

  # call test body

  jal   x1, test_entry

  # use return value from test_entry (a0) as exit code

test_return:
  sw    a0, -4(x0)